var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"열흘 전","JPN":"10日前","ENG":"Ten days earlier","TWN":"十天前","SCN":"十天前","DEU":"Ten days earlier","FRA":"Ten days earlier"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 재건 도시 <color=#ffd34c>ARC-NL1</color>\\n구 네덜란드, 암스테르담","JPN":"管理局再建都市<color=#ffd34c>ARC-NL1</color>\\n旧オランダ、アムステルダム","ENG":"[[","TWN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n舊荷蘭 阿姆斯特丹","SCN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n旧荷兰，阿姆斯特丹","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"다국적 합자 대침식 연구소 – 퓨처 앳 워\\n<color=#ffd34c>제3지부 항공 우주 연구소</color>","JPN":"多国籍合資対侵食戦研究所 - フューチャーアットウォー\\n<color=#ffd34c>第3支部航空宇宙研究所</color>","ENG":"[[","TWN":"跨國合資反侵蝕研究所-天啟兵器\\n<color=#ffd34c>第三分部航空航太研究所</color>","SCN":"跨国合资反侵蚀研究所-天启兵器\\n<color=#ffd34c>第三分部航空航天研究所</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그래서……?","JPN":"で……？","ENG":"So...?","TWN":"所以……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"샤레이드 한복판에서 벡터 변환 중이던 망원 렌즈를 저격으로 멈추게 했다는 거야?","JPN":"シャレードの真ん中でベクター変換中だった望遠レンズを狙撃で止めたっていうの？","ENG":"Are you saying you managed to stop the Zoom Lens mid-vector conversion with a sniper shot right in the middle of Charade?","TWN":"你是說在查雷德中心，靠狙擊成功阻止了望遠鏡頭的向量轉換？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 결과적으로는 그렇게 됐단다.","JPN":"まあ、結果的にそうなったわね。","ENG":"Well, that's what happened, in the end.","TWN":"嗯，事情就是這樣發生的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"너, 지금 제 정신이야? 잘못해서 망원 렌즈에 맞았으면, 어쩔 뻔했어?","JPN":"あんた、気は確か？　間違って望遠レンズに当たったらどうするつもりだったの？","ENG":"Are you out of your mind? What if you had missed and hit the Zoom Lens?","TWN":"你瘋了嗎？如果你射偏了打到望遠鏡頭怎麼辦？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"만약 그랬으면, 샤레이드 한 구역이 지도에서 사라져 버렸을지도 모른다고!","JPN":"シャレードのど真ん中にでっかい穴ができたかもしれないのよ！","ENG":"If that had happened, an entire section of Charade could have been wiped off the map!","TWN":"如果那樣，整個查雷德的區域可能會被徹底剷平！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"내가 말했잖아! 민간 피해는 최소화하라고 말이야!","JPN":"言ったでしょ！　民間の被害は最小限にしろって！","ENG":"Didn't I tell you? Keep civilian casualties to a minimum!","TWN":"我不是告訴過你了嗎？務必將平民傷亡降到最低！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 이거 이상하구나.","JPN":"ふふ、おかしいわねえ。","ENG":"Fu fu. That's strange.","TWN":"呵呵，真奇怪。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"쥐새끼는 소리에 민감하다던데, 왜 우리 쥐새끼는 말귀를 잘 못 알아들을까?","JPN":"ネズミは音に敏感だって言うけど、どうしてこっちのネズミは音に鈍感なのかしら。","ENG":"They say rats are sensitive to sound, so why is our little rat so bad at understanding words?","TWN":"老鼠對聲音很敏感，為什麼我們的老鼠卻這麼不聽話呢？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"はあ？","ENG":"What did you say?","TWN":"你說什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"나야말로 말했잖니? 망원 렌즈가 아니라, 그걸 들고 있던 꼬맹이를 노린 거라고.","JPN":"私こそ言ったはずよ。望遠レンズではなく、それを持っていたチビちゃんを狙ったって。","ENG":"I told you, didn't I? I wasn't aiming for the Zoom Lens. I was aiming for the kid holding it.","TWN":"我不是告訴你了嗎？我沒瞄準望遠鏡頭，是瞄準拿著它的小鬼。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그것도 일부러 크게 다치지 않게끔, 탄도를 계산해서 빗맞힌 거란다.","JPN":"しかもわざと大怪我しないように、弾道を計算して外したのよ。","ENG":"And I made sure to miss intentionally, calculating the trajectory so she wouldn't get seriously injured.","TWN":"而且我特意計算了軌跡故意射偏，避免她受傷。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그게 아니면, 지금 내가 가꾼 장미들의 실력을 의심하는 거니?","JPN":"それとも、私が育てたバラたちの腕を疑っているのかしら？","ENG":"Unless, of course, you're questioning the skill of the roses I've cultivated.","TWN":"當然，除非你質疑我培育的玫瑰的技術。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"네가 가꾼 장미? 허! 아주 웃기고 자빠졌네……!","JPN":"あんたが育てたバラ？　は！　笑わせないで……！","ENG":"The roses you cultivated? Ha! That's ridiculous...!","TWN":"你培育的玫瑰？哈！荒謬……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"역시 범죄자는 사고방식이 다른 가봐? 양심이 있다면 말은 똑바로 하는 게 어때?","JPN":"さすがに犯罪者は考え方が普通と違うみたいね？　良心ってものがあるなら正直に言ったらどう？","ENG":"Guess criminals really do think differently. If you had any conscience, you'd speak more honestly.","TWN":"看來罪犯果然思維不同。如果你有點良心，說話會誠實一點。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그건 알파트릭스의 유산을 멋대로 훔쳐다 쓰고 있을 뿐이잖아?","JPN":"アルファトリックスの遺産を勝手に盗んで使っているだけだって。","ENG":"You're just stealing Alphatrix's legacy and using it for your own purposes.","TWN":"你不過是在偷用阿爾法崔克斯的遺產，拿來為自己謀利。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"자기 성과도 아닌 걸, 부풀려서 말하면 부끄럽지도 않아?","JPN":"自分の成果でもないのに、そんなことを言って恥ずかしくないの？","ENG":"Aren't you ashamed to claim something that's not even your own work?","TWN":"不是自己的成績，卻誇大其詞地說出來，不覺得羞愧嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그것도 그런 말도 안 되는 미친 기술을……!","JPN":"しかも、あんなマッドサイエンス……！","ENG":"Especially when it's some insane technology like that...!","TWN":"尤其這還是什麼瘋狂科技……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 구 관리국의 공학자 출신이라고 해도, 역시 자기 분야가 아니면 문외한인가 보네.","JPN":"ふふ、旧管理局の工学者出身とはいっても、専門分野以外は何もわかっていないみたいね。","ENG":"Fu fu. Even if you were a former engineer of the Old Administration, I guess you're clueless when it's not your field.","TWN":"呵呵。即使你曾是舊管理局的工程師，別的領域你還真是一竅不通。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 도박꾼이 남긴 클론은 엄연한 실패작이었단다.","JPN":"あのギャンブラーが残したクローンは失敗作だったわ。","ENG":"The clones left behind by that degenerate were nothing but failures.","TWN":"那個墮落者留下的克隆人不過是失敗品。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"꽃의 품종이 뛰어날 뿐, 그 꽃을 가꿀 주인이 엉망이었으니까 말이지.","JPN":"優れていたのは花の品種だけで、その花を育てる主がクズなんだもの。","ENG":"The flowers were splendid, but the gardener was a mess.","TWN":"花朵再美，園丁卻一團糟。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"아무리 색과 향이 화려하다고 하더라도, 일찍 시들어 버린다면 가치가 없는 법이지.","JPN":"いくら色と香りが華麗だとしても、すぐに枯れてしまっては価値なんてない。","ENG":"No matter how vibrant the colors or how fragrant the scent, a flower that wilts too soon is worthless.","TWN":"不管顏色多鮮豔，香味多芬芳，枯萎太早的花就是沒價值。"},"stage":{"bg":"ALPHA_05","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};